import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        FastScanner fs=new FastScanner(System.in);
        int T=fs.nextInt();
        StringBuilder sb=new StringBuilder();
        while(T-- >0){
            int N=fs.nextInt();
            int K=fs.nextInt();
            int[] a=new int[N];
            for(int i=0;i<N;i++) a[i]=fs.nextInt();
            int[] b=a.clone();
            Arrays.sort(b);
            @SuppressWarnings("unchecked")
            ArrayList<Integer>[] orig=new ArrayList[K];
            @SuppressWarnings("unchecked")
            ArrayList<Integer>[] sorted=new ArrayList[K];
            for(int i=0;i<K;i++){orig[i]=new ArrayList<>();sorted[i]=new ArrayList<>();}
            for(int i=0;i<N;i++){
                orig[i%K].add(a[i]);
                sorted[i%K].add(b[i]);
            }
            boolean ok=true;
            for(int r=0;r<K && ok;r++){
                Collections.sort(orig[r]);
                Collections.sort(sorted[r]);
                if(!orig[r].equals(sorted[r])) ok=false;
            }
            sb.append(ok?"yes":"no").append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner{
        private final BufferedInputStream in;
        private final byte[] buffer=new byte[1<<16];
        private int ptr=0, len=0;
        FastScanner(InputStream is){in=new BufferedInputStream(is);}        
        private int readByte() throws IOException{if(ptr>=len){len=in.read(buffer);ptr=0;if(len==-1) return -1;}return buffer[ptr++];}
        int nextInt() throws IOException{int c,sign=1; do{c=readByte();}while(c<=32 && c!=-1); if(c=='-'){sign=-1;c=readByte();}
            int val=0; while(c>32 && c!=-1){val=val*10+(c-'0');c=readByte();}
            return val*sign;}
    }
}

