const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=data[idx++];
let out=[];
for(let t=0;t<T;t++){
  const N=data[idx++];
  const K=data[idx++];
  const a=data.slice(idx,idx+N); idx+=N;
  const b=[...a].sort((x,y)=>x-y);
  const bucketsOrig=Array.from({length:K},()=>[]);
  const bucketsSorted=Array.from({length:K},()=>[]);
  for(let i=0;i<N;i++) bucketsOrig[i%K].push(a[i]);
  for(let i=0;i<N;i++) bucketsSorted[i%K].push(b[i]);
  let ok=true;
  for(let r=0;r<K && ok;r++){
    bucketsOrig[r].sort((x,y)=>x-y);
    bucketsSorted[r].sort((x,y)=>x-y);
    if(bucketsOrig[r].length!==bucketsSorted[r].length){ok=false;break;}
    for(let i=0;i<bucketsOrig[r].length;i++) if(bucketsOrig[r][i]!==bucketsSorted[r][i]){ok=false;break;}
  }
  out.push(ok?'yes':'no');
}
console.log(out.join('\n'));
